import React from 'react';
import { RangePickerTrigger } from './RangePickerTrigger';
import { RangePickerPanel } from './RangePickerPanel';
import type { RangePickerContextType } from './Context';
import { RangePickerContextProvider } from './Context';
import type { RangePickerContextProps, RangePickerProps } from './types';
import { useRangePicker } from './useRangePicker';
import { RangePickerFooter } from './RangePickerFooter';
import '../style';

export const RangePickerProvider = React.forwardRef<
  RangePickerContextType,
  React.PropsWithChildren<RangePickerContextProps>
>(({ children, ...props }, ref) => {
  const rangePickerCtx = useRangePicker(props);
  React.useImperativeHandle(ref, () => rangePickerCtx);
  return <RangePickerContextProvider value={rangePickerCtx}>{children}</RangePickerContextProvider>;
});

export const RangePicker = (props: RangePickerProps) => {
  const { dateRender, startOfWeek, hideWeekNumbers, janX, ranges, renderExtraFooter, ...restProps } = props;
  return (
    <RangePickerProvider {...restProps}>
      <RangePickerTrigger
        {...props}
        panel={
          <>
            <RangePickerPanel
              dateRender={dateRender}
              startOfWeek={startOfWeek}
              hideWeekNumbers={hideWeekNumbers}
              janX={janX}
            />
            <RangePickerFooter ranges={ranges} renderExtraFooter={renderExtraFooter} />
          </>
        }
      />
    </RangePickerProvider>
  );
};
